import React from "react"
import Link from "../IntlLink"
import { useStaticQuery, graphql } from "gatsby"
import PubImage from "../PubImage"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function MenuCard({ name, lang }) {
	
	const cx = classNames.bind(styles);

	const data = useStaticQuery(
		graphql`
			query {
				site {
					siteMetadata {
						nav {
							group
							items {
								name
								url
							}
						}
						collections {
							collection
							placeholder
						}
					}
				}
				research1: allMdx(
					filter: {fields: {collection: {in: ["dp", "pierspectives"]}}},
					sort: {fields: frontmatter___date, order: DESC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							cover {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					}
				}
				research2: allMdx(
					filter: {fields: {collection: {in: ["abridged", "thaipublica"]}}},
					sort: {fields: frontmatter___date, order: DESC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							cover {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					}
				}
				eventUpcoming: allMdx(
					filter: {fields: {collection: {in: ["conferences", "workshops", "seminars", "exchange"]}, isFuture: {eq: true}}},
					sort: {fields: frontmatter___date, order: ASC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							cover {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					}
				}
				eventLatest: allMdx(
					filter: {fields: {collection: {in: ["conferences", "workshops", "seminars", "exchange"]}, isFuture: {eq: false}}},
					sort: {fields: frontmatter___date, order: DESC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							cover {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					}
				}
				blog: allMdx(
					filter: {fields: {collection: {eq: "blog"}}},
					sort: {fields: frontmatter___date, order: DESC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							cover {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
							gallery {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					}
				}
				announcements: allMdx(
					filter: {fields: {collection: {eq: "announcements"}}},
					sort: {fields: frontmatter___date, order: DESC},
					limit: 1
				) {
					nodes {
						fields {
							slug
							collection
						}
						frontmatter {
							title
							gallery {
								childImageSharp {
									gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
								}
							}
						}
					} 
				}
			}
		`
	)

	const items = data.site.siteMetadata.nav.filter(x => x.group === name)
	
	const pubdata = {
		dp: {
			th: "Discussion paper ",
			en: "discussion paper",
		},
		pierspectives: {
			th: "PIERspectives ",
			en: "PIERspectives",
		},
		abridged: {
			th: "aBRIDGEd ",
			en: "aBRIDGEd",
		},
		thaipublica: {
			th: 'บทความเศรษฐศาสตร์เข้า "ท่า" ',
			en: "ThaiPublica article",
		},
		conferences: {
			th: "งานประชุมวิชาการ",
			en: "conference",
		},
		workshops: {
			th: "งานประชุมเชิงปฏิบัติการ",
			en: "workshop",
		},
		seminars: {
			th: "งานสัมมนา",
			en: "PIER Economic Seminar",
		},
		exchange: {
			th: "งานสัมมนา",
			en: "PIER Research Exchange",
		},
		blog: {
			th: "บทความ",
			en: "blog post",
		},
		announcements: {
			th: "ประกาศ",
			en: "announcement",
		},
	}

	let node1 = null
	let node2 = null
	
	switch(name) {
		case "Research":
			node1 = data.research1.nodes[0]
			node2 = data.research2.nodes[0]
			break;
		case "Events":
			node1 = data.eventUpcoming.nodes[0]
			node2 = data.eventLatest.nodes[0]
			break;
		case "About Us":
			node1 = data.blog.nodes[0]
			node2 = data.announcements.nodes[0]
			break;
		default:
			node1 = null
			node2 = null
			break;
	}

	function MenuPub({ node, caption={th: "%xล่าสุด", en: "Latest %x"}}) {
		if (!node)
			return <div>xxx</div>
		return(
			<Link to={node.fields.slug} className="nolinkcolor nohover">
				<div className={"zoom-container " + cx("pub")}>
					<PubImage f={node.frontmatter} collection={node.fields.collection} style={"square"} />
					<div className={cx("type")}>
						<span className={"blob-small-span " + cx("overrideBlob")}>
							{
								caption[lang].replace('%x', pubdata[node.fields.collection][lang])
							}
						</span>
					</div>
					<div className={cx("title")}>
						{node.frontmatter.title}
					</div>
				</div>
			</Link>
		)
	}

	return(
		<div className={cx("menuCard")}>
			<div className={cx("gridItem", "nav")}>
				<div className={cx("group")}>
					{items[0].group}
				</div>
				<div className={cx("items")}>
				{items[0].items.map((item, i) =>
					<div className={cx("item")} key={`item${i}`}><Link to={item.url}>{item.name}</Link></div>
				)}
				</div>
			</div>
			<div className={cx("gridItem", "right")}>
				<MenuPub node={node1} caption={name === "Events" ? {th: "%xต่อไป", en: "Upcoming %x"} : undefined}/>
				<MenuPub node={node2}/>
			</div>
		</div>
	)
}