export default function Share({ inline, id }) {

  const url = typeof window !== 'undefined' ? window.location.href : '';

  return(
    <div className={cx("shareContainer", "noprint", {inline: inline})} id={id}>
      <FacebookShareButton
        url={url}
      >
        <Icon type="facebook" inline={inline} />
      </FacebookShareButton>
      <TwitterShareButton url={url}>
        <Icon type="twitter" inline={inline} />
      </TwitterShareButton>
      <LinkedinShareButton url={url}>
        <Icon type="linkedin" inline={inline} />
      </LinkedinShareButton>
      <EmailShareButton url={url}>
        <Icon type="email" inline={inline} />
      </EmailShareButton>
    </div>
  )

}