import React from "react"
import { Highlight, Snippet } from "react-instantsearch-dom"
import FA from "../FA"
import Link from "../IntlLink"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"


export default function Hits({ hits, lang, noMargin=false }) {

	const cx = classNames.bind(styles);

	const placeholder = {
		dp: "cap",
		thaipublica: "anchor",
		pierspectives: "telescope",
		pages: "page",
		announcements: "announcements",
		seminars: "presentation",
		workshops: "meeting",
		conferences: "keynote",
	}

	const typetag = {
		dp: "DP",
		pierspectives: "PIERspective",
		abridged: "aBRIDGEd",
		thaipublica: 'เศรษฐศาสตร์เข้า "ท่า"',
		members: "Member",
		pages: "Page",
		announcements: "Announcement",
		posts: "Blog",
		seminars: "Seminar",
		workshops: "Workshop",
		conferences: "Conference",
	}

	function Body({ hit }) {
		// console.log(hit)
		if (hit._snippetResult && hit._snippetResult.body) {
			const filterMatch = hit._snippetResult.body.filter(bodyitem => bodyitem.matchLevel !== "none")
			if (filterMatch.length > 0) {
    		return(
    			<React.Fragment>
    				...
    				<Snippet
    					hit={hit}
    					attribute={'body'}
    					tagName="mark"
    					separator=" ... "
    				/>
    				...
    			</React.Fragment>
    		)
    	}
    	else {
    		return(
    			<React.Fragment>
    				{hit._snippetResult.body[0].value.substring(0, 100) + " ... "}
    				{hit._snippetResult.body[0].value.length < 50 &&
    					hit._snippetResult.body.length > 1 && 
	    				hit._snippetResult.body[1].value.substring(0, 50) + " ... "
    				}
    			</React.Fragment>
    		)
    	}
		}
		return null
	}

	return(
		<div className={cx("container", {nomargin: noMargin})}>
			{hits.map((hit, i) => {
				return(
		      <Link to={hit.page_path} className="nolinkcolor nohover" key={`hit${i}`}>
			      <div className={cx("card", hit.collection)}>
							<div className={cx("image")}>
			      		{
			      			hit.img_url
			      			? <img src={hit.img_url} alt={hit.title} />
			      			: <div className={cx("placeholder")}><FA icon={placeholder[hit.collection] || "page"} /></div>
			      		}
			      	</div>
			      	<div className={cx("mainCard")}>
				      	<div className={cx("title")}>
					      	<Highlight hit={hit} attribute={'title'} tagName="mark" />
					      	<span className={"blob-small-span " + cx("blob")}>{typetag[hit.collection]}</span>
				      	</div>
				      	{hit.date_formatted && <div className={"date " + cx("date")}>{hit.date_formatted}</div>}
				      	<div className={cx("body")}>
					      	<Body hit={hit} />
				      	</div>
				      </div>
			      </div>
		      </Link>
				)
			})}
		</div>
	)

}