import React from "react"
import { use100vh } from "react-div-100vh"
import { MDXProvider } from "@mdx-js/react"
import { useStaticQuery, graphql } from "gatsby"
import { GatsbyImage, getSrc } from "gatsby-plugin-image"
import SEO from "../SEO"
import Header from "../Header"
import Banner from "../Banner"
import Share from "../Share"
import SearchBar from "../../components/SearchBar"
import Footer from "../Footer"
import SideNav from "../SideNav"
import { LazyPlotly, LazyHighcharts } from '../Plots'
import Link from "../IntlLink"
import { Helmet } from "react-helmet"
import { mdxComponents, typesenseComponents } from "../../util"
import kebabCase from "lodash/kebabCase"

import { createMuiTheme, ThemeProvider } from '@material-ui/core/styles';
import styles from '../../styles/_variables.module.scss'

import "./styles.scss"

export default function Layout({ lang, children, indexThis=true, shareThis=true, isList=false, noSearch=false, noBanner=false, showCover=false,
	mdx,
	metadata,
	series,
	placeholder=(metadata && metadata.placeholder),
	title, subtitle, pathname, description, image, collection,
	top,
	customTitle,
}) {

	if (isList) {
		indexThis = false
		shareThis = false
	}

	let components = {
		...mdxComponents,
		LazyPlotly,
		LazyHighcharts,
		Link,
	}
	if (indexThis) {
		components = {...components, ...typesenseComponents}
	}

	const height = use100vh()
  const fullHeight = height || '100vh'

  React.useEffect(() => {
  	if (typeof window !== 'undefined') {
			document.body.style.position = '';
			document.body.style.top = '';
			document.documentElement.classList.remove("sidenav-on")
  	}
  })

  const theme = createMuiTheme({
	  palette: {
	    primary: {
	      main: styles.primaryColor,
	    },
	    secondary: {
	      main: styles.secondaryColor,
	    },
	  },
	  typography: {
	  	fontFamily: "Dindan",
	  },
	});

	const placeholderPics = useStaticQuery(graphql`
    query {
      allFile(filter: {sourceInstanceName: {eq: "images"}, relativeDirectory: {eq: "placeholder"}}) {
        nodes {
          name
          publicURL
        }
      }
    }
  `)

	const f = mdx && mdx.frontmatter

	const finalTitle = title || (f && f.title) || (metadata && metadata.title)
	const finalPathname = pathname || (mdx && mdx.fields && mdx.fields.slug) || (metadata && metadata.url)
	const finalDescription = description || (f && f.subtitle) || (metadata && metadata.subtitle)
	const finalImage = image
											|| (f && f.image && f.image.publicURL)
											|| (f && f.cover && f.cover.publicURL)
											|| (placeholder && placeholderPics.allFile.nodes.filter(p => p.name === placeholder)[0].publicURL)
	
	return(
		<React.Fragment>
			<Helmet>
				<link rel="icon" href="/favicon.svg" />
				<link rel="icon" type="image/png" sizes="32x32" href="/favicon-32x32.png" />
				<link rel="icon" type="image/png" sizes="16x16" href="/favicon-16x16.png" />
				<link rel="apple-touch-icon" sizes="180x180" href="/apple-touch-icon.png" />
				<link rel="mask-icon" href="/maskedicon.svg" color="#5bbad5" />
				<link rel="manifest" href="/site.webmanifest" />
				<meta name="msapplication-TileColor" content="#da532c" />
				<meta name="theme-color" content="#ffffff" />
			</Helmet>
			<SEO
				title={finalTitle}
				pathname={finalPathname}
				description={finalDescription}
				image={finalImage}
			/>
			<ThemeProvider theme={theme}>
				<SideNav />
				{/* TODO: Chrome on iPad still bad when change rotation with short pages */}
				<div id="main" style={{minHeight: fullHeight}}>
					<Header lang={lang} noSearch={noSearch} />
					<div id="menu-leek">
						<div id="body">
							{!noBanner &&
								<React.Fragment>
									<Banner
										type="small"
										subtitle={subtitle || (series && `PIER ${metadata.title}`) || (metadata && metadata.subtitle)}
										to={pathname || (series && `${metadata.url}${kebabCase(series)}/`) || (metadata && metadata.url)}
										subto={series && metadata && metadata.url}
										shorturl={mdx?.fields?.shorturl}
									>
										{indexThis && customTitle
											? <span data-typesense-field="title">{title || (series && `${series} Series`) || (metadata && metadata.title)}</span>
											: title || (series && `${series} Series`) || (metadata && metadata.title)
										}	
										{indexThis &&
											<React.Fragment>
												<span hidden data-typesense-field="collection">{collection || (metadata && metadata.collection)}</span>
												{series && <span hidden data-typesense-field="series">{`${series} Series`}</span>}
											</React.Fragment>
										}
									</Banner>
									<SearchBar />
									{showCover && f.cover &&
										<React.Fragment>
											<GatsbyImage image={f.cover.childImageSharp.gatsbyImageData} alt={finalTitle} />
											<span hidden data-typesense-field="img_url">{getSrc(f.cover.childImageSharp.thumbnail)}</span>
										</React.Fragment>
									}
								</React.Fragment>
							}
							{top}
							<MDXProvider components={components}>
								<div className="layout-content" id="layout-content">
									{shareThis && <Share id="share" />}
									<div className="flex-padding">
										<div className={"content" + (customTitle ? " content-more-margin" : "")}>
											{children}
										</div>
									</div>
								</div>
							</MDXProvider>
						</div>
						<Footer lang={lang} />
					</div>
				</div>
			</ThemeProvider>
		</React.Fragment>
	)
}
