import React from "react"
import { navigate } from "gatsby"
import TypesenseInstantSearchAdapter from "typesense-instantsearch-adapter"
import { InstantSearch, connectStats, connectSearchBox, connectHits, Configure } from "react-instantsearch-dom"
import Hits from "../../components/Hits"

import Dialog from '@material-ui/core/Dialog';
import DialogTitle from '@material-ui/core/DialogTitle';
import DialogContent from '@material-ui/core/DialogContent';
import TextField from '@material-ui/core/TextField';
import FormGroup from '@material-ui/core/FormGroup';
import Button from '@material-ui/core/Button';
import { withStyles } from '@material-ui/styles';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import CloseIcon from '@material-ui/icons/Close';
import MoreHorizIcon from '@material-ui/icons/MoreHoriz';
import IconButton from '@material-ui/core/IconButton';

import { typesenseSearchConfig } from "../../util"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

const dialogStyles = {
	dialogPaper: {
		minHeight: '90vh',
		maxHeight: '90vh',
	},
};

function SearchModal({ classes, open, handleClose, lang }) {

	const cx = classNames.bind(styles);
  
	const typesenseInstantsearchAdapter = new TypesenseInstantSearchAdapter(typesenseSearchConfig)
	const searchClient = typesenseInstantsearchAdapter.searchClient

	const largeScreen = useMediaQuery('(min-width:700px)');

  const SearchBox = ({ currentRefinement, isSearchStalled, refine }) => {

		React.useEffect(() => {
			if (typeof window !== 'undefined') {
				if (largeScreen)
					document.getElementById("popup-search").focus()
			}
		})

		return(
			<FormGroup noValidate action="" role="search">
				<TextField
					id="popup-search"
					type="search"
					value={currentRefinement}
					onChange={event => refine(event.target.value)}
					variant="outlined"
					label="Search"
					size="small"
					fullWidth
				/>
				{/*isSearchStalled ? 'My search is stalled' : ''*/}
			</FormGroup>
		)
	}

	const hitsPerPage = 5

	function goToFullSearch() {
		navigate(
			`${lang === "th" ? '/' : '/en/'}search/
				${document.getElementById("popup-search").value &&
					`?q=${document.getElementById("popup-search").value}`}`
		)
	}

	const Stats = ({ processingTimeMS, nbHits }) => {
		if (nbHits > hitsPerPage)
			return(
				<div className={cx("more")}>
					<Button onClick={goToFullSearch}>
						View all {nbHits - hitsPerPage} results
					</Button>
				</div>
			)
		return null
	}

	const CustomSearchBox = connectSearchBox(SearchBox)
	const CustomHits = connectHits(Hits)
	const CustomStats = connectStats(Stats)

  return(
    <Dialog
			open={open}
			onClose={handleClose}
			maxWidth="md"
			fullWidth={true}
			fullScreen={!largeScreen}
			classes={largeScreen ? { paper: classes.dialogPaper } : {}}
			// classes={{ paper: classes.dialogPaper }}
		>
			<InstantSearch searchClient={searchClient} indexName={`all_${lang}`}>
				<Configure
					hitsPerPage={hitsPerPage}
				/>
				<DialogTitle>
					<div className={cx("title")}>
						<div className="searchGroup">
							<CustomSearchBox />
							{/* <CustomStats /> */}
						</div>
						<div>
							<IconButton size="small" aria-label="more" onClick={goToFullSearch}>
								<MoreHorizIcon />
							</IconButton>
							<span className={cx("closeButton")}>
								<IconButton size="small" aria-label="close" onClick={handleClose}>
									<CloseIcon />
								</IconButton>
							</span>
						</div>
					</div>
				</DialogTitle>
				<DialogContent>
					<CustomHits lang={lang} noMargin={true} />
					<CustomStats />
				</DialogContent>
			</InstantSearch>
			{/* <DialogActions>
				<Button
					onClick={() => navigate(
						`${lang === "th" ? '/' : '/en/'}search/
							${document.getElementById("popup-search").value &&
								`?q=${document.getElementById("popup-search").value}`}`
					)}
					color="primary"
				>
					View More
				</Button>
			</DialogActions> */}
    </Dialog>
  )

}

export default withStyles(dialogStyles)(SearchModal)