import React from "react"
import { GatsbyImage } from "gatsby-plugin-image"
import { useStaticQuery, graphql } from "gatsby"

export default function PubImage({ f, collection, style="normal", ...rest }) {

	const placeholderPics = useStaticQuery(graphql`
    query {
      site {
        siteMetadata {
          collections {
            collection
            placeholder
          }
          series {
            series
            placeholder
          }
        }
      }
      allFile(filter: {sourceInstanceName: {eq: "images"}, relativeDirectory: {eq: "placeholder"}}) {
        nodes {
          name
          childImageSharp {
            normal: gatsbyImageData(layout: CONSTRAINED, width: 500)
            square: gatsbyImageData(layout: CONSTRAINED, width: 400, height: 400)
            cover: gatsbyImageData(layout: CONSTRAINED, width: 600, height: 315)
            fullwidth: gatsbyImageData(layout: FULL_WIDTH)
          }
        }
      }
    }
  `)

  let fallbackName = placeholderPics.site.siteMetadata.collections.filter(c => c.collection === collection)[0].placeholder
  const seriesOverride = placeholderPics.site.siteMetadata.series.filter(s => s.series === f.series)
  if (seriesOverride.length > 0) {
    fallbackName = seriesOverride[0].placeholder
  }
  
  let pic
  if (f.cover) {
    if (!f.cover.childImageSharp)
      console.log(f)
    pic = f.cover.childImageSharp.gatsbyImageData
  }
  else if (f.gallery) {
    pic = f.gallery[0].childImageSharp.gatsbyImageData
  }
  else {
    pic = placeholderPics.allFile.nodes.filter(p => fallbackName ? p.name === fallbackName : p.name === "generic")[0].childImageSharp[style]
  }

  return <GatsbyImage image={pic} alt={f.title} className={"zoom"} {...rest} />

}