import React from "react"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"


export default function MobileNav() {

	const cx = classNames.bind(styles);

	function bar(e) {
		if (document.documentElement.style.getPropertyValue('--header-pos') === "fixed")
			e.stopPropagation();
	}

	function foo(e) {
		const showMenu = e.target.checked
		if (showMenu) {
			const move = window.pageYOffset
			document.documentElement.classList.add("sidenav-on")
			document.body.style.position = 'fixed';
			document.body.style.top = `-${move}px`;
			document.getElementById("menu-leek").style.transform = "translateX(-250px)"
			document.getElementById("sidenav").style.transform = "translateX(-250px)"
		}
		else {
			document.getElementById("menu-leek").style.transform = "none"
			document.getElementById("sidenav").style.transform = "none"
			const move = document.body.style.top;
			document.body.style.position = '';
			document.body.style.top = '';
			document.documentElement.classList.remove("sidenav-on")
			window.scrollTo(0, parseInt(move || '0') * -1);
			document.documentElement.style.setProperty('--header', "0px")
			document.documentElement.style.setProperty('--header-pos', 'fixed')
		}
	}

	return(
		<div className={cx("menuToggle", "noprint")} onChange={foo} onClick={bar} onKeyDown={bar} role="button" tabIndex={0}>
			<input type="checkbox"/>
			<span className={cx("top")}></span>
			<span className={cx("middle")}></span>
			<span className={cx("bottom")}></span>
		</div>
	)

}