import React from "react"
import Link from "../IntlLink"
import { useStaticQuery, graphql } from "gatsby"
import { use100vh } from "react-div-100vh"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function SideNav() {

	const cx = classNames.bind(styles);

	const data = useStaticQuery(
		graphql`
			query {
				site {
					siteMetadata {
						nav {
							group
							items {
								name
								url
							}
						}
					}
				}
			}
		`
	)

	function foo(e) {
		const group = e.target.closest('.group')
		const body = group.children[1]
		group.classList.toggle(cx('collapsed'))
		if (body.style.maxHeight === "0px")
			body.style.maxHeight = body.scrollHeight + "px"
		else
			body.style.maxHeight = "0px"
	}

	const height = use100vh()
  const fullHeight = height || '100vh'

	return(
		<div id="sidenav" style={{height: fullHeight}}>
			<div className={cx("sidenavContainer")}>
				{data.site.siteMetadata.nav.map((group, i) =>
					<div className={cx("group", "collapsed", "ggg")} key={`group${i}`} onClick={foo} onKeyDown={foo} role="button" tabIndex={0}>
						<div className={cx("head")}>
							<div>{group.group}</div>
							<div className={cx("arrow")}>
								<svg aria-hidden="true" role="img" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 256 512">
									<path fill="currentColor" d="M224.3 273l-136 136c-9.4 9.4-24.6 9.4-33.9 0l-22.6-22.6c-9.4-9.4-9.4-24.6 0-33.9l96.4-96.4-96.4-96.4c-9.4-9.4-9.4-24.6 0-33.9L54.3 103c9.4-9.4 24.6-9.4 33.9 0l136 136c9.5 9.4 9.5 24.6.1 34z" />
								</svg>
							</div>
						</div>
						<div className={cx("body")} style={{maxHeight: "0px"}}>
							{group.items.map((item, j) =>
								<Link to={item.url} key={`item${j}`}><div className={cx("item")}>{item.name}</div></Link>
							)}
						</div>
					</div>
				)}
			</div>
		</div>
	)

}