import React from "react"
import { changeLocale } from "gatsby-plugin-intl"
import FA from "../../components/FA"
import SearchModal from "../../components/SearchModal"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function LangSelect({ lang, noSearch }) {

	const cx = classNames.bind(styles);
	const btnRefs = {th: React.useRef(null), en: React.useRef(null)}

	const [open, setOpen] = React.useState(false)

	// TODO: still weird transition when cilcked

	React.useLayoutEffect(() => {
		const intl = window.___gatsbyIntl
		// btnRefs[intl.language].current.classList.add(cx('selected'))
		if (!intl.languages.includes('th')) {
			btnRefs.th.current.setAttribute('disabled', 'true')
		}
		if (!intl.languages.includes('en')) {
			btnRefs.en.current.setAttribute('disabled', 'true')
		}
	}, [])

	function handleClick(e, locale) {
		if (e.target.attributes.disabled === undefined) {
			changeLocale(locale)
		}
	}

	function handleSearch() {
		setOpen(true)
	}

	return(
		<div className={cx('langSelect', 'noprint')}>
			<div className={cx('box', 'searchBox')}>
				<span role="button" className={cx('searchButton')} disabled={noSearch} onClick={noSearch ? undefined : handleSearch} onKeyDown={noSearch ? undefined : handleSearch} tabIndex={0}>
					<FA icon="search" />
				</span>
				<SearchModal open={open} handleClose={() => setOpen(false)} lang={lang} />
			</div>
			<div role="button" ref={btnRefs.th} className={cx('box', 'langBlock', {'selected': lang === "th"})} onClick={e => handleClick(e, "th")} onKeyDown={e => handleClick(e, "th")} tabIndex={0}>TH</div>
			<div role="button" ref={btnRefs.en} className={cx('box', 'langBlock', {'selected': lang === "en"})} onClick={e => handleClick(e, "en")} onKeyDown={e => handleClick(e, "en")} tabIndex={0}>EN</div>
		</div>
	)

}