import React from "react"
import LangSelect from "../LangSelect"
import Link from "../IntlLink"
import Logo from "../Logo"
import Hamburger from "../Hamburger"
import MenuCard from "../MenuCard"
import { useStaticQuery, graphql } from "gatsby"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function Header({ lang, noSearch }) {

	const cx = classNames.bind(styles);

	const data = useStaticQuery(
		graphql`
			query {
				site {
					siteMetadata {
						nav {
							group
						}
					}
				}
			}
		`
	)

	// const menu = React.createRef()
	const header = React.createRef()
	const bottomborder = React.createRef()

	let oldY = 0
	let lastTurn = 0
	let oldScroll = 0
	let headerPos = 0

	function handleHeaderClick() {
		if (window.innerWidth <= 700 && window.pageYOffset !== headerPos) {
			// document.documentElement.style.setProperty('--header', window.pageYOffset + "px")
			document.documentElement.style.setProperty('--header-pos', 'absolute')
			window.scrollTo({ top: headerPos, behavior: 'smooth' })
			document.documentElement.style.setProperty('--header', "0px")
			document.documentElement.style.setProperty('--header-pos', 'fixed')
		}
		else {
			window.scrollTo({ top: 0, behavior: 'smooth' })
		}
	}

	function handleScroll() {

		if (document.documentElement.classList.contains("sidenav-on") || header.current === null)
			return

		const headerHeight = header.current.offsetHeight
		const y = Math.max(window.pageYOffset, 0)

		// bottom orange line
		if (window.innerWidth < 700) {
			const searchbar = document.getElementById("searchbar")
			if (searchbar.getBoundingClientRect().y + searchbar.offsetHeight > bottomborder.current.getBoundingClientRect().y + bottomborder.current.offsetHeight) {
				bottomborder.current.classList.add("hidden")
			}
			else {
				bottomborder.current.classList.remove("hidden")
			}
		}

		if (oldY > y) {
			if (oldScroll === 1) {
				// switch to scroll up
				oldScroll = 0
				if (y - lastTurn > headerHeight) {
					// console.log("update lastTurn to", lastTurn)
					document.documentElement.style.setProperty('--header', (y - headerHeight) + "px")
					document.documentElement.style.setProperty('--header-pos', 'absolute')
					headerPos = y - headerHeight
				}
				lastTurn = y
			}
			else {
				// continue to scroll up
				// console.log("up... diff =", lastTurn - y)
				const margin = oldY - y
				if (lastTurn - y > headerHeight - margin || y < headerPos) {
					// can hide
					document.documentElement.style.setProperty('--header', "0px")
					document.documentElement.style.setProperty('--header-pos', 'fixed')
					headerPos = y
				}
			}

		}
		else if (oldY < y) {
			if (oldScroll === 0) {
				// switch to scroll down
				// console.log("switch to down")
				oldScroll = 1
				// console.log("update lastTurn to", lastTurn)
				if (lastTurn - y > headerHeight) {
					document.documentElement.style.setProperty('--header', y + "px")
					document.documentElement.style.setProperty('--header-pos', 'absolute')
					headerPos = y
				}
				else if (lastTurn < y) {
					document.documentElement.style.setProperty('--header', Math.max(0, y - headerHeight) + "px")
					document.documentElement.style.setProperty('--header-pos', 'absolute')
					headerPos = Math.max(0, y - headerHeight)
				}
				lastTurn = y
			}
			else {
				document.documentElement.style.setProperty('--header', headerPos + "px")
				document.documentElement.style.setProperty('--header-pos', 'absolute')
			}
		}

		oldY = y
	}

	if (typeof window !== 'undefined') {
		oldY = window.pageYOffset
		document.documentElement.style.setProperty('--header', "0px")
		document.documentElement.style.setProperty('--header-pos', 'absolute')
		window.onscroll = handleScroll
		// scrollStop(handleStopScroll)
	}

	function Arrow() {
		return(
			<div className={cx("arrow")}>
				<svg xmlns="http://www.w3.org/2000/svg" version="1.1" viewBox="0 0 2 1" overflow="visible">
					<polygon points="1,0 2,1 0,1" />
					{/*<path d="M0,1 L1,0 L2,1" />*/}
				</svg>
			</div>
		)
	}

	function DropDownMenu({ name }) {
		return(
			<div className={cx("dropItem")}>
				<div className={cx("navDrop")}>
					<MenuCard name={name} lang={lang} />
				</div>
				<Arrow />
			</div>
		)
	}

	return(
		<div className={cx("header")} ref={header} onClick={handleHeaderClick} onKeyDown={handleHeaderClick} role="button" tabIndex={0}>
			<div className={cx("topBorder", "noprint")} />
			
				<div className="flex-padding">

					<div className={cx("navbar")}>

						<LangSelect lang={lang} noSearch={noSearch} />
						<Hamburger />
						
						<div className={cx("navgroup", "leftgroup")}>
							<div className={cx("navitem", "rightBorder")}>
								<Link to="#">{data.site.siteMetadata.nav[0].group}</Link>
								<DropDownMenu name={data.site.siteMetadata.nav[0].group} />
							</div>
							<div className={cx("navitem")}>
								<Link to="#">{data.site.siteMetadata.nav[1].group}</Link>
								<DropDownMenu name={data.site.siteMetadata.nav[1].group} />
							</div>
						</div>

						<div />

						<div><Logo lang={lang} /></div>

						<div />

						<div className={cx("navgroup")}>
							<div className={cx("navitem", "rightBorder")}>
								<Link to="#">{data.site.siteMetadata.nav[2].group}</Link>
								<DropDownMenu name={data.site.siteMetadata.nav[2].group} />
							</div>
							<div className={cx("navitem")}>
								<Link to="#">{data.site.siteMetadata.nav[3].group}</Link>
								<DropDownMenu name={data.site.siteMetadata.nav[3].group} />
							</div>
						</div>

					</div>
				</div>
			<div className={cx("hidden", "noprint", "bottomBorder")} ref={bottomborder} />
		</div>
	)

}