import React from "react"
import Link from "../IntlLink"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function Banner({ type, subtitle, to, subto, shorturl, children }) {

	const cx = classNames.bind(styles);
  const url = typeof window !== 'undefined' ? ((shorturl && window.location.origin + shorturl) || window.location.href) : 'https://www.pier.or.th/'

	to = to || "#"

	if (type === "small") {
		return(
			<div className={cx("container")}>
				<div className="flex-padding">
					<div className={cx("banner")}>
						<div className={cx("content")}>
							<div>
								<div className={cx("smallTitle")}>
									<Link to={to} className="nolinkcolor nohover">
										{children}
									</Link>
								</div>
								{subtitle &&
									<div className={cx("smallSubtitle")}>
										<Link to={subto} className="nolinkcolor nohover">
											{subtitle}
										</Link>
									</div>
								}
							</div>
						</div>
						<div className={cx("qr", "printonly")}>
							<img src={`https://api.qrserver.com/v1/create-qr-code/?size=70x70&margin=0&data=${url}`} />
						</div>
					</div>
				</div>
			</div>
		)
	}

}